function getPageFromHash() {
  let hash = window.location.hash.replace(/^#\/?/, '');
  return pages.includes(hash) ? hash : 'home';
}

function showPage(name) { var p = window.location.pathname; var inPages = p.indexOf('/pages/') >= 0; if (name === 'home') { window.location.href = (inPages ? '../' : '') + 'index.html'; } else { window.location.href = (inPages ? '../' : '') + 'pages/' + name + '.html'; } }

