// Package enquiry -> direct WhatsApp with package name pre-filled
function enquirePackage(packageName) {
  const text = encodeURIComponent(`Assalam-o-Alaikum Sanayah Travels!\n\nI would like to enquire about the *${packageName}* package. Could you please share the complete details, current pricing, and availability?\n\nThank you!`);
  window.open(`https://wa.me/923002816459?text=${text}`, '_blank');
}

// Form submit
function submitForm() {
  var name = document.getElementById('cf-name').value.trim();
  var email = document.getElementById('cf-email').value.trim();
  var phone = document.getElementById('cf-phone').value.trim();
  var msg = document.getElementById('cf-msg').value.trim();
  if (!name || !phone) { alert('Please fill in at least your name and phone number.'); return; }
  var service = document.getElementById('cf-service').value;
  apiSubmitContact({ name, email, phone, message: msg, service });

  var emailCfg;
  try { emailCfg = JSON.parse(localStorage.getItem('sanayah_email') || '{}'); } catch(e) { emailCfg = {}; }

  if (emailCfg && emailCfg.key && emailCfg.service && emailCfg.template) {
    if (!window.emailjs) {
      var s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js';
      s.onload = function() { emailjs.init(emailCfg.key); doSendEmail(); };
      document.body.appendChild(s);
    } else {
      doSendEmail();
    }
    function doSendEmail() {
      emailjs.send(emailCfg.service, emailCfg.template, {
        to_email: emailCfg.recipient,
        from_name: name,
        from_email: email || 'Not provided',
        from_phone: phone,
        service_type: service || 'General Inquiry',
        message: msg || 'No message provided.'
      }).then(function() {
        showToast('Message sent! We\'ll get back to you shortly.');
      }).catch(function(e) {
        console.error('EmailJS error:', e);
        fallbackWhatsApp();
      });
    }
  } else {
    fallbackWhatsApp();
  }

  document.getElementById('cf-name').value = '';
  document.getElementById('cf-email').value = '';
  document.getElementById('cf-phone').value = '';
  document.getElementById('cf-msg').value = '';

  function fallbackWhatsApp() {
    var text = encodeURIComponent('Hello Sanayah Travels!\n\nName: ' + name + '\nPhone: ' + phone + '\nEmail: ' + (email || 'Not provided') + '\nService: ' + (service || 'General Inquiry') + '\n\nMessage: ' + (msg || 'No message provided.'));
    window.open('https://wa.me/923002816459?text=' + text, '_blank');
    showToast('Message sent! We\'ll get back to you shortly.');
  }
}

function showToast(msg, type) {
  var el = document.getElementById('toast');
  if (!el) return;
  el.textContent = msg;
  el.className = 'toast show' + (type ? ' ' + type : '');
  clearTimeout(el._timer);
  el._timer = setTimeout(function() { el.classList.remove('show'); }, 4000);
}

// Scroll animations
function triggerAnimations() {
  document.querySelectorAll('.fade-up').forEach(el => {
    const rect = el.getBoundingClientRect();
    if (rect.top < window.innerHeight - 60) {
      el.classList.add('visible');
    }
  });
}

// Back to top
window.addEventListener('scroll', () => {
  const btn = document.getElementById('backTop');
  if (btn) btn.classList.toggle('show', window.scrollY > 400);
  triggerAnimations();
});

