function getAirlines() {
  let data = localStorage.getItem('sanayah_airlines');
  if (data) {
    try { var parsed = JSON.parse(data); if (parsed && parsed.length) { parsed.forEach(a => { if (!a.data && a.logo) a.data = a.logo; }); return parsed; } } catch(e) {}
  }
  // Auto-seed from defaults and persist to localStorage
  const airlines = [];
  const seen = new Set();
  DEFAULT_AIRLINES.forEach(a => {
    if (!seen.has(a.name)) { seen.add(a.name); airlines.push({ name: a.name, data: a.data }); }
  });
  if (airlines.length) saveAirlines(airlines);
  return airlines;
}

function saveAirlines(airlines) {
  try { localStorage.setItem('sanayah_airlines', JSON.stringify(airlines)); } catch(e) { console.error('localStorage quota exceeded or save failed'); }
}

// Seed localStorage airlines from existing HTML on first run
function seedAirlinesFromHTML() {
  if (localStorage.getItem('sanayah_airlines')) return;
  const airlines = [];
  const seen = new Set();
  DEFAULT_AIRLINES.forEach(a => {
    if (!seen.has(a.name)) {
      seen.add(a.name);
      airlines.push({ name: a.name, data: a.data });
    }
  });
  if (airlines.length) {
    saveAirlines(airlines);
  }
}

// Star rating handler
let currentRating = 0;
document.addEventListener('DOMContentLoaded', () => {
  const stars = document.querySelectorAll('.star-rating .star');
  if (stars.length) {
    stars.forEach(s => {
      s.addEventListener('click', () => {
        currentRating = parseInt(s.getAttribute('data-val'));
        stars.forEach(st => {
          st.classList.toggle('active', parseInt(st.getAttribute('data-val')) <= currentRating);
          st.innerHTML = parseInt(st.getAttribute('data-val')) <= currentRating ? '&#9733;' : '&#9734;';
        });
      });
      s.addEventListener('mouseenter', () => {
        const val = parseInt(s.getAttribute('data-val'));
        stars.forEach(st => {
          st.innerHTML = parseInt(st.getAttribute('data-val')) <= val ? '&#9733;' : '&#9734;';
        });
      });
      s.addEventListener('mouseleave', () => {
        stars.forEach(st => {
          st.innerHTML = parseInt(st.getAttribute('data-val')) <= currentRating ? '&#9733;' : '&#9734;';
        });
      });
    });
  }
});

function submitReview() {
  const name = document.getElementById('rv-name').value.trim();
  const city = document.getElementById('rv-city').value.trim();
  const text = document.getElementById('rv-text').value.trim();
  if (!name) { alert('Please enter your name.'); return; }
  if (currentRating === 0) { alert('Please select a rating.'); return; }
  if (!text) { alert('Please write your review.'); return; }
  const review = { name, city: city || 'Unknown', rating: currentRating, text };
  apiSubmitReview(review);
  const reviews = getReviews();
  reviews.unshift({
    name, city: city || 'Unknown',
    rating: currentRating, text,
    date: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
    approved: false
  });
  saveReviews(reviews);
  document.getElementById('rv-name').value = '';
  document.getElementById('rv-city').value = '';
  document.getElementById('rv-text').value = '';
  currentRating = 0;
  document.querySelectorAll('.star-rating .star').forEach(st => { st.innerHTML = '&#9734;'; st.classList.remove('active'); });
  renderReviews();
  const toast = document.getElementById('toast');
  toast.textContent = '&#10003; Review submitted! Awaiting approval.';
  toast.classList.add('show');
  setTimeout(() => { toast.classList.remove('show'); toast.textContent = 'Message sent! We\'ll get back to you shortly.'; }, 4000);
}

function renderReviews() {
  const container = document.getElementById('reviews-container');
  if (!container) return;
  const reviews = getReviews().filter(r => r.approved);
  if (!reviews.length) {
    container.innerHTML = '<p style="text-align:center;color:var(--text-muted);grid-column:1/-1;padding:40px 0">No reviews yet. Be the first to share your experience! &#9733;</p>';
    return;
  }
  container.innerHTML = reviews.map(r => {
    const initial = r.name.charAt(0).toUpperCase();
    const starsHtml = Array.from({length:5}, (_,i) => i < r.rating ? '&#9733;' : '&#9734;').join('');
    return `<div class="review-card">
      <div class="stars">${starsHtml}</div>
      <div class="review-text">"${r.text}"</div>
      <div class="review-author">
        <div class="review-avatar">${initial}</div>
        <div>
          <div class="review-name">${r.name}</div>
          <div class="review-loc">?? ${r.city}</div>
          <div class="review-date">${r.date}</div>
        </div>
      </div>
    </div>`;
  }).join('');
}

