// Apply WA number site-wide
function applyWANumber() {
  const wa = getWANumber().replace(/[^0-9]/g, '');
  const formatted = '+' + wa.slice(0,2) + ' ' + wa.slice(2,5) + ' ' + wa.slice(5);
  document.querySelectorAll('a[href*="wa.me"]').forEach(a => {
    a.href = a.href.replace(/wa\.me\/[\d]+/, 'wa.me/' + wa);
  });
  document.querySelectorAll('a[href^="tel:"]').forEach(a => {
    a.href = 'tel:+' + wa;
    a.textContent = a.textContent.replace(/[\+\(\)\s\d\-]{7,}/g, formatted);
  });
  document.querySelectorAll('.cta-contact, [data-content="phone"]').forEach(a => {
    a.textContent = a.textContent.replace(/[\+\(\)\s\d\-]{7,}/g, formatted);
    if (a.href && a.href.indexOf('tel:') === 0) a.href = 'tel:+' + wa;
  });
  // Replace any remaining phone text patterns
  document.querySelectorAll('p, span, div, h3, h4, li').forEach(function(el) {
    if (el.children.length === 0 && el.textContent.match(/\+?\d[\s\d\-\(\)]{8,}\d/)) {
      el.textContent = el.textContent.replace(/[\+\(\)\s\d\-]{7,}/g, formatted);
    }
  });
}

// Apply about text
function applyAboutText() {
  const ab = getAboutText();
  const el = document.querySelector('#page-about .about-story > div:last-child');
  if (!el) return;
  const ps = el.querySelectorAll('p');
  if (ps.length >= 3) {
    ps[0].textContent = ab.p1;
    ps[1].textContent = ab.p2;
    ps[2].textContent = ab.p3;
  }
  const titleEl = document.querySelector('#page-about .section-title');
  if (titleEl) titleEl.textContent = ab.title;
}

// Refresh airline brand strip from localStorage
function refreshAirlineStrip() {
  const inner = document.querySelector('.brand-strip-inner');
  if (!inner) return;
  const airlines = getAirlines();
  inner.innerHTML = '';
  [...airlines, ...airlines].forEach(a => {
    const span = document.createElement('span');
    const img = document.createElement('img');
    img.src = a.data || a.logo || '';
    img.alt = a.name;
    img.title = a.name;
    if (!img.src) img.style.display = 'none';
    span.appendChild(img);
    inner.appendChild(span);
  });
}

