async function syncFromBackend() {
  try {
    var r = await apiGetReviews(true); if (r && r.length) localStorage.setItem('sanayah_reviews', JSON.stringify(r));
    var al = await apiGetAirlines(); if (al && al.length) localStorage.setItem('sanayah_airlines', JSON.stringify(al));
    var b = await apiGetBlog(); if (b) localStorage.setItem('sanayah_blog', JSON.stringify(b));
    var fq = await apiGetFaq(); if (fq && fq.length) localStorage.setItem('sanayah_faq', JSON.stringify(fq));
    var qa = await apiGetQa(); if (qa && qa.length) localStorage.setItem('sanayah_qa', JSON.stringify(qa));
    var pgs = await apiGetPages(); if (pgs && Object.keys(pgs).length) localStorage.setItem('sanayah_pages', JSON.stringify(pgs));
    var seo = await apiGetSetting('sanayah_seo'); if (seo) localStorage.setItem('sanayah_seo', JSON.stringify(seo));
    var soc = await apiGetSetting('sanayah_social'); if (soc) localStorage.setItem('sanayah_social', JSON.stringify(soc));
    var cc = await apiGetSetting('sanayah_contact'); if (cc) localStorage.setItem('sanayah_contact', JSON.stringify(cc));
    var chat = await apiGetSetting('sanayah_chatconfig'); if (chat) localStorage.setItem('sanayah_chatconfig', JSON.stringify(chat));
  } catch(e) {}
  initDynamicContent();
}
function renderBlog() {
  var grid = document.getElementById('blog-grid');
  if (!grid) return;
  var blog = getBlog();
  if (!blog.posts || !blog.posts.length) {
    grid.innerHTML = '<p style="color:#64748b;text-align:center;padding:40px;grid-column:1/-1">No blog posts yet. Check back soon!</p>';
    return;
  }
  var html = '';
  for (var i = 0; i < blog.posts.length; i++) {
    var p = blog.posts[i];
    var excerpt = (p.content || '').substring(0, 150);
    if (p.content && p.content.length > 150) excerpt += '...';
    html += '<div class="blog-card"><div class="blog-card-body"><h3>' + (p.title||'').replace(/</g,'&lt;') + '</h3><div class="blog-meta">' + (p.date||'') + '</div><p>' + excerpt.replace(/</g,'&lt;') + '</p></div></div>';
  }
  grid.innerHTML = html;
}

function initDynamicContent() {
  // SEO
  var seo = getSeoSettings();
  if (seo.title) document.title = seo.title;
  if (seo.description) {
    var m = document.querySelector('meta[name="description"]') || document.createElement('meta');
    if (!m.parentNode) { m.name = 'description'; document.head.appendChild(m); }
    m.content = seo.description;
  }
  if (seo.keywords) {
    var k = document.querySelector('meta[name="keywords"]') || document.createElement('meta');
    if (!k.parentNode) { k.name = 'keywords'; document.head.appendChild(k); }
    k.content = seo.keywords;
  }
  if (seo.og_title) {
    var ogt = document.querySelector('meta[property="og:title"]') || document.createElement('meta');
    if (!ogt.parentNode) { ogt.setAttribute('property','og:title'); document.head.appendChild(ogt); }
    ogt.content = seo.og_title;
  }
  if (seo.og_description) {
    var ogd = document.querySelector('meta[property="og:description"]') || document.createElement('meta');
    if (!ogd.parentNode) { ogd.setAttribute('property','og:description'); document.head.appendChild(ogd); }
    ogd.content = seo.og_description;
  }
  if (seo.og_image) {
    var ogi = document.querySelector('meta[property="og:image"]') || document.createElement('meta');
    if (!ogi.parentNode) { ogi.setAttribute('property','og:image'); document.head.appendChild(ogi); }
    ogi.content = seo.og_image;
  }
  if (seo.ga_id) {
    if (!document.getElementById('ga-script')) {
      var ga = document.createElement('script'); ga.id = 'ga-script'; ga.async = true;
      ga.src = 'https://www.googletagmanager.com/gtag/js?id=' + seo.ga_id;
      document.head.appendChild(ga);
      var gai = document.createElement('script'); gai.id = 'ga-init';
      gai.textContent = "window.dataLayer=window.dataLayer||[];function gtag(){dataLayer.push(arguments)}gtag('js',new Date());gtag('config','" + seo.ga_id + "');";
      document.head.appendChild(gai);
    }
  }
  if (seo.sc_verify) {
    var sc = document.querySelector('meta[name="google-site-verification"]') || document.createElement('meta');
    if (!sc.parentNode) { sc.name = 'google-site-verification'; document.head.appendChild(sc); }
    sc.content = seo.sc_verify.replace(/<[^>]*>/g,'').replace(/content="([^"]*)"/,'$1').trim();
  }

  // Favicon
  var favicon = localStorage.getItem('sanayah_favicon');
  var favLink = document.getElementById('favicon-link');
  if (favicon && favLink) { favLink.href = favicon; } else if (favLink) { favLink.href = ''; }

  // Logo
  var logo = getSiteLogo();
  var logoEls = document.querySelectorAll('.logo-wrap svg, .logo-wrap img');
  if (logo && logoEls.length) {
    logoEls.forEach(function(el) {
      var img = document.createElement('img');
      img.src = logo; img.alt = 'Sanayah Travels'; img.style.height = el.style.height || '50px';
      img.style.width = 'auto'; img.style.borderRadius = '8px';
      el.parentNode.replaceChild(img, el);
    });
  }
  var footerLogo = document.querySelector('.footer-logo svg, .footer-logo img');
  if (logo && footerLogo) {
    var img = document.createElement('img');
    img.src = logo; img.alt = 'Sanayah Travels'; img.style.height = '40px';
    img.style.width = 'auto'; img.style.borderRadius = '6px';
    footerLogo.parentNode.replaceChild(img, footerLogo);
  }

  // IATA
  var iata = getIataLogo();
  if (iata) {
    var iataEl = document.querySelector('.iata-logo, [class*="iata"]');
    if (iataEl) {
      if (iataEl.tagName === 'IMG') iataEl.src = iata;
      else { var img = document.createElement('img'); img.src = iata; img.style.height = '40px'; img.style.width = 'auto'; iataEl.parentNode.replaceChild(img, iataEl); }
    }
  }

  // Social Links
  var social = getSocialLinks();
  var socialContainers = document.querySelectorAll('.social-links');
  socialContainers.forEach(function(container) {
    var links = container.querySelectorAll('a');
    links.forEach(function(a) {
      var cls = a.className;
      var key = '';
      if (cls.indexOf('fb')>=0) key = 'facebook';
      else if (cls.indexOf('ig')>=0) key = 'instagram';
      else if (cls.indexOf('tt')>=0) key = 'twitter';
      else if (cls.indexOf('li')>=0) key = 'linkedin';
      else if (cls.indexOf('yt')>=0) key = 'youtube';
      else if (cls.indexOf('tk')>=0 || cls.indexOf('tt2')>=0) key = 'tiktok';
      if (key && social[key]) a.href = social[key];
    });
  });

  // Clear wrong PTCL from localStorage if saved
  try { var saved = JSON.parse(localStorage.getItem('sanayah_contact')); if (saved && saved.ptcl && saved.ptcl.indexOf('300') >= 0) { saved.ptcl = '92 21 34832373'; localStorage.setItem('sanayah_contact', JSON.stringify(saved)); } } catch(e) {}
  // Contact Info
  var contact = getContactInfo();
  if (contact.email) {
    document.querySelectorAll('[data-content="email"]').forEach(function(el) { el.textContent = contact.email; });
    document.querySelectorAll('a[href^="mailto:"]').forEach(function(a) { a.href = 'mailto:' + contact.email; });
  }
  if (contact.address) {
    document.querySelectorAll('[data-content="address"]').forEach(function(el) { el.textContent = contact.address; });
  }
  if (contact.address) {
    document.querySelectorAll('[data-content="address"]').forEach(function(el) { el.textContent = contact.address; });
  }
  // PTCL - always use this number regardless of admin settings
  var ptclNum = '92 21 34832373';
  document.querySelectorAll('[data-content="ptcl"]').forEach(function(el) { el.textContent = ptclNum; });
  document.querySelectorAll('a[href^="tel:"]').forEach(function(a) {
    if (a.textContent.indexOf('PTCL')>=0 || a.textContent.indexOf('ptcl')>=0) {
      a.href = 'tel:' + ptclNum.replace(/[^0-9+]/g,'');
      a.textContent = a.textContent.replace(/\+?92[\s\d\-]+/g, ptclNum);
    }
  });
  // topbar PTCL span
  document.querySelectorAll('.topbar span').forEach(function(sp) {
    if (sp.textContent.indexOf('PTCL') >= 0) {
      var link = sp.querySelector('a');
      if (link) { link.textContent = ptclNum; link.href = 'tel:' + ptclNum.replace(/[^0-9+]/g,''); }
      else sp.innerHTML = sp.innerHTML.replace(/\+?92[\s\d\-]+/g, ptclNum);
    }
  });
  if (contact.hours) {
    document.querySelectorAll('[data-content="hours"]').forEach(function(el) { el.textContent = contact.hours; });
    // Update topbar timing span
    topbarSpans.forEach(function(sp) {
      var txt = sp.textContent;
      if ((txt.indexOf('Mon') >= 0 || txt.indexOf('Sat') >= 0 || txt.indexOf('12pm') >= 0 || txt.indexOf('12') >= 0) && txt.indexOf('PTCL') < 0 && txt.indexOf('@') < 0) {
        sp.textContent = ' ' + contact.hours;
      }
    });
  }

  // WhatsApp float button
  var wa = getWANumber();
  var waEls = document.querySelectorAll('.wa-float, [href*="wa.me"]');
  waEls.forEach(function(el) {
    el.href = 'https://wa.me/' + wa.replace(/[^0-9]/g,'');
  });

  // Page Content - replace data-content attributes
  var els = document.querySelectorAll('[data-content]');
  var pages = getPageContent();
  els.forEach(function(el) {
    var key = el.getAttribute('data-content');
    var page = el.getAttribute('data-page') || 'home';
    if (pages[page] && pages[page][key]) {
      el.textContent = pages[page][key];
    }
  });

  // Reviews Display
  var reviewsContainer = document.getElementById('reviews-display');
  if (reviewsContainer) {
    var reviews = getReviews().filter(function(r) { return r.approved; });
    if (reviews.length) {
      var html = '';
      reviews.forEach(function(r) {
        var stars = '';
        for (var si = 0; si < 5; si++) stars += si < r.rating ? '&#9733;' : '&#9734;';
        html += '<div class="testi-card"><div class="stars">' + stars + '</div><p>"' + r.text.replace(/</g,'&lt;') + '"</p><div class="testi-author"><div class="author-avatar">' + (r.name ? r.name.charAt(0).toUpperCase() : '?') + '</div><div><div class="author-name">' + (r.name||'').replace(/</g,'&lt;') + '</div><div class="author-loc">' + (r.city||'').replace(/</g,'&lt;') + '</div></div></div></div>';
      });
      reviewsContainer.innerHTML = html;
    }
  }

  // Address removal
  var addrEl = document.querySelector('[data-content="address"]');
  if (addrEl) {
    var parent = addrEl.parentNode;
    if (parent && !addrEl.textContent.trim()) parent.style.display = 'none';
  }
}

// ------------------------------------------
// HOMEPAGE POPUP
// ------------------------------------------
function showHomePopup() {
  var cfg;
  try { cfg = JSON.parse(localStorage.getItem('sanayah_popup') || '{}'); } catch(e) { cfg = {}; }
  if (!cfg.enabled) return;
  var popup = document.getElementById('homePopup');
  var textEl = document.getElementById('popupText');
  var imgEl = document.getElementById('popupImg');
  var wrapEl = document.getElementById('popupImgWrap');
  if (!popup) return;
  textEl.innerHTML = (cfg.text || '').replace(/\n/g, '<br>');
  if (cfg.image) {
    imgEl.src = cfg.image;
    wrapEl.style.display = 'block';
  } else {
    wrapEl.style.display = 'none';
  }
  popup.style.display = 'flex';
}
window.closeHomePopup = function() {
  var popup = document.getElementById('homePopup');
  if (popup) popup.style.display = 'none';
};

// ------------------------------------------
// CHATBOT WIDGET
// ------------------------------------------
window.toggleChatbot = function() {
  var panel = document.getElementById('chatbotPanel');
  if (!panel) return;
  panel.classList.toggle('open');
  if (panel.classList.contains('open')) {
    var msgs = document.getElementById('chatbotMsgs');
    if (!msgs.children.length) {
      addChatMsg('Hi! I\'m the Sanayah Travels assistant. Ask me about Umrah packages, flights, visas, tours, or anything travel-related!', 'bot');
    }
    document.getElementById('chatbotInput').focus();
  }
};

function addChatMsg(text, type) {
  var msgs = document.getElementById('chatbotMsgs');
  if (!msgs) return;
  var div = document.createElement('div');
  div.className = 'chat-msg ' + type;
  div.textContent = text;
  msgs.appendChild(div);
  msgs.scrollTop = msgs.scrollHeight;
}

function getBotReply(msg) {
  var qa;
  try { qa = JSON.parse(localStorage.getItem('sanayah_qa') || '[]'); } catch(e) { qa = []; }
  var lower = msg.toLowerCase();
  for (var i = 0; i < qa.length; i++) {
    if (lower.indexOf(qa[i].key) !== -1) return qa[i].reply;
  }
  return null;
}

window.sendChatbotMsg = function() {
  var input = document.getElementById('chatbotInput');
  var text = input.value.trim();
  if (!text) return;
  input.value = '';
  addChatMsg(text, 'user');

  // Check Q&A first
  var reply = getBotReply(text);
  if (reply) {
    setTimeout(function() { addChatMsg(reply, 'bot'); }, 400);
    return;
  }

  // Try AI API
  var cfg;
  try { cfg = JSON.parse(localStorage.getItem('sanayah_chatconfig') || '{}'); } catch(e) { cfg = {}; }
  if (cfg && cfg.apiKey) {
    addChatMsg('...', 'typing');
    var typingEl = document.querySelector('.chat-msg.typing:last-child');

    if (cfg.provider === 'gemini') {
      var url = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=' + cfg.apiKey;
      var body = JSON.stringify({ contents: [{ parts: [{ text: (cfg.systemPrompt || '') + '\n\nUser: ' + text }] }] });
      fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: body })
        .then(function(r) { return r.json(); })
        .then(function(d) {
          if (typingEl) typingEl.remove();
          var r = d.candidates && d.candidates[0] && d.candidates[0].content && d.candidates[0].content.parts && d.candidates[0].content.parts[0] ? d.candidates[0].content.parts[0].text : 'Sorry, I couldn\'t process that. Please contact us directly.';
          addChatMsg(r, 'bot');
        })
        .catch(function() {
          if (typingEl) typingEl.remove();
          addChatMsg('Sorry, I\'m having trouble connecting. Please try again or contact us directly.', 'bot');
        });
    } else if (cfg.provider === 'deepseek') {
      var url = 'https://api.deepseek.com/chat/completions';
      var body = JSON.stringify({ model: 'deepseek-chat', messages: [{ role: 'system', content: cfg.systemPrompt || '' }, { role: 'user', content: text }] });
      fetch(url, { method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + cfg.apiKey }, body: body })
        .then(function(r) { return r.json(); })
        .then(function(d) {
          if (typingEl) typingEl.remove();
          if (d.error) { console.error('DeepSeek API error:', d.error); addChatMsg('AI Error: ' + (d.error.message || JSON.stringify(d.error)), 'bot'); return; }
          var r = d.choices && d.choices[0] && d.choices[0].message ? d.choices[0].message.content : 'Sorry, I couldn\'t process that. Please contact us directly.';
          addChatMsg(r, 'bot');
        })
        .catch(function(e) {
          if (typingEl) typingEl.remove();
          console.error('Fetch error:', e);
          addChatMsg('Connection error: ' + e.message, 'bot');
        });
    } else {
      if (typingEl) typingEl.remove();
      addChatMsg('Please contact us via WhatsApp or phone for any questions!', 'bot');
    }
  } else {
    addChatMsg('Please contact us via WhatsApp or phone for any questions!', 'bot');
  }
};

document.addEventListener('DOMContentLoaded', syncFromBackend);

// Visitor tracking
(function trackVisitor() {
  try {
    var stored = JSON.parse(localStorage.getItem('sanayah_visitors') || '[]');
    var last = stored.length ? stored[0] : null;
    if (last && (Date.now() - last.time < 60000)) return;
    function saveVisitor(v) {
      stored.unshift(v);
      if (stored.length > 50) stored = stored.slice(0, 50);
      localStorage.setItem('sanayah_visitors', JSON.stringify(stored));
      apiTrackVisitor(v);
    }
    var xhr = new XMLHttpRequest();
    xhr.open('GET', 'https://ip-api.com/json/?fields=query,country,city,regionName', true);
    xhr.timeout = 5000;
    xhr.onload = function() {
      try {
        var data = JSON.parse(xhr.responseText);
        var v = { ip: data.query || 'Unknown', country: data.country || '', city: data.city || '', region: data.regionName || '', time: Date.now(), page: window.location.pathname.split('/').pop() || 'index' };
        saveVisitor(v);
      } catch(e) { saveVisitor({ ip: 'Unknown', country: '', city: '', region: '', time: Date.now(), page: window.location.pathname.split('/').pop() || 'index' }); }
    };
    xhr.onerror = function() { saveVisitor({ ip: 'Unknown', country: '', city: '', region: '', time: Date.now(), page: window.location.pathname.split('/').pop() || 'index' }); };
    xhr.ontimeout = function() { saveVisitor({ ip: 'Unknown', country: '', city: '', region: '', time: Date.now(), page: window.location.pathname.split('/').pop() || 'index' }); };
    xhr.send();
  } catch(e) {}
})();

